import{_ as e,o as i,c as s,a2 as o}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"Seguridad","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/07-seguridad.md","filePath":"bases-de-datos/redis/07-seguridad.md","lastUpdated":1782521464000}'),r={name:"bases-de-datos/redis/07-seguridad.md"};function t(n,a,l,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h1><p>Redis debe tratarse como infraestructura sensible. Por defecto es muy rapido y directo, pero una exposicion mal configurada puede ser critica.</p><h2 id="red" tabindex="-1">Red <a class="header-anchor" href="#red" aria-label="Permalink to &quot;Red&quot;">​</a></h2><p>Medidas basicas:</p><ul><li>No exponer Redis publicamente.</li><li>Escuchar solo en interfaces internas.</li><li>Usar firewall o security groups.</li><li>Separar entornos.</li></ul><p>Configuracion orientativa:</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bind 127.0.0.1</span></span>
<span class="line"><span>protected-mode yes</span></span></code></pre></div><h2 id="autenticacion" tabindex="-1">Autenticacion <a class="header-anchor" href="#autenticacion" aria-label="Permalink to &quot;Autenticacion&quot;">​</a></h2><p>Redis moderno soporta ACLs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ACL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SETUSER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">password</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~app:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +del</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +expire</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ACL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LIST</span></span></code></pre></div><p>Evita usar un unico usuario administrador para todas las aplicaciones.</p><h2 id="tls" tabindex="-1">TLS <a class="header-anchor" href="#tls" aria-label="Permalink to &quot;TLS&quot;">​</a></h2><p>En entornos donde el trafico cruza redes no confiables, usa TLS. Tambien es habitual cuando Redis esta gestionado por un proveedor cloud.</p><h2 id="comandos-peligrosos" tabindex="-1">Comandos peligrosos <a class="header-anchor" href="#comandos-peligrosos" aria-label="Permalink to &quot;Comandos peligrosos&quot;">​</a></h2><p>Algunos comandos deben restringirse:</p><ul><li><code>FLUSHALL</code></li><li><code>FLUSHDB</code></li><li><code>CONFIG</code></li><li><code>KEYS</code></li><li><code>SHUTDOWN</code></li></ul><h2 id="secretos" tabindex="-1">Secretos <a class="header-anchor" href="#secretos" aria-label="Permalink to &quot;Secretos&quot;">​</a></h2><p>No guardes secretos permanentes en Redis salvo que haya una razon clara y controles adecuados.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa ACLs por aplicacion.</li><li>Limita comandos permitidos.</li><li>Protege Redis a nivel de red.</li><li>Rota credenciales.</li><li>Monitoriza comandos administrativos.</li><li>Manten Redis actualizado.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Exponer Redis a Internet.</li><li>Compartir la misma password entre servicios.</li><li>Permitir <code>FLUSHALL</code> a usuarios de aplicacion.</li><li>No cifrar trafico sensible.</li><li>Guardar datos sensibles sin retencion ni cifrado externo.</li></ul>`,22)])])}const k=e(r,[["render",t]]);export{u as __pageData,k as default};
